import { useEffect, useState } from 'react';
import axiosInstance from '../axiosConfig';
import { useAuth } from '../context/AuthContext';
import UserCreateBookingForm from '../components/UserCreateBookingForm';
import UserBookingList from '../components/UserBookingList';

const CreateBooking = () => {
  const { user } = useAuth();
  const [bookings, setBookings] = useState([]);
  const [editingBooking, setEditingBooking] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchBookings = async () => {
      if (!user) return;
      setLoading(true);
      try {
        const response = await axiosInstance.get('/api/bookings', {
          headers: { Authorization: `Bearer ${user.token}` },
        });
        setBookings(response.data);
      } catch (error) {
        alert('Failed to fetch bookings.');
      } finally {
        setLoading(false);
      }
    };

    fetchBookings();
  }, [user]);

  if (!user) {
    return <div className="text-center mt-20">Please log in to manage your bookings.</div>;
  }

  return (
    <div className="min-h-screen bg-[#D7EFFF] flex items-center justify-center p-6">
      <div className="relative w-full max-w-4xl rounded-3xl bg-white/90 border border-[#c8e1fb] px-6 py-12 sm:px-14 overflow-hidden shadow-2xl">
        <img
          src="/BookingBg.jpg"
          alt=""
          aria-hidden="true"
          className="pointer-events-none select-none absolute left-1/2 top-1/2 w-[140%] max-w-none -translate-x-1/2 -translate-y-1/2 opacity-30"
        />
        <div className="relative space-y-10">
          <div>
            <p className="text-sm uppercase tracking-widest text-[#546b86] text-center mb-2">
              User - Create/Edit Booking Page
            </p>
            <h1 className="text-4xl font-semibold text-center text-[#0d2440] tracking-wide">
              Get Your Removal Quotes
            </h1>
          </div>

          <UserCreateBookingForm
            bookings={bookings}
            setBookings={setBookings}
            editingBooking={editingBooking}
            setEditingBooking={setEditingBooking}
          />

          <div className="pt-6 border-t border-white/60">
            <div className="flex items-center justify-between mb-4">
              <h2 className="text-2xl font-semibold text-[#0d2440]">Your Bookings</h2>
              {editingBooking && (
                <span className="text-sm text-[#546b86]">Editing current booking...</span>
              )}
            </div>
            {loading ? (
              <p className="text-center text-[#0d2440]">Loading bookings...</p>
            ) : (
              <UserBookingList
                bookings={bookings}
                setBookings={setBookings}
                setEditingBooking={setEditingBooking}
              />
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default CreateBooking;
